// Pointwise (1x1) conv2d, stride=1, tiled-streaming contract.
//   IC=256, OC=1024, IH=IW=14, OH=OW=14, MP=4.
//   channel_tile=32 -> IN_BEATS=8, OUT_BEATS=32 per pixel.
// Latency: IN_BEATS + OC_PASSES * (MP*K_TOTAL + 6) = 8 + 256*1030 = 263688.
// Improvement: weight ROM read isolated in a no-reset always block so the
// BRAM output register is inferable (async reset blocks Xilinx BRAM regs).
module node_conv_262 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);
    localparam IC = 256, OC = 1024, IH = 14, IW = 14, OH = 14, OW = 14;
    localparam KH = 1, KW = 1, SH = 1, SW = 1, PH = 0, PW = 0;
    localparam K_TOTAL      = IC * KH * KW;
    localparam MP           = 4;
    localparam OC_PASSES    = (OC + MP - 1) / MP;
    localparam CHANNEL_TILE = 32;
    localparam IN_BEATS     = (IC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam OUT_BEATS    = (OC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam TILE_BITS    = CHANNEL_TILE * 8;
    localparam OH_OW        = OH * OW;
    localparam SCALE_MULT  = 3999;
    localparam SCALE_SHIFT = 19;
    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = PROD_W + $clog2(K_TOTAL);
    localparam integer BIAS_W        = 32;
    localparam integer BIASED_W      = ((ACC_W > BIAS_W) ? ACC_W : BIAS_W) + 1;
    localparam integer SCALE_MAG_W   = $clog2(SCALE_MULT + 1);
    localparam integer SCALE_CONST_W = SCALE_MAG_W + 1;
    localparam integer SCALED_W      = BIASED_W + SCALE_CONST_W;
    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF = {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 = SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};
    (* rom_style = "block", ram_style = "block" *) reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [31:0] biases  [0:OC-1];
    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_262_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_262_bias.hex", biases);
    end
    localparam ST_LOAD=3'd0, ST_RUN=3'd1, ST_BIAS=3'd2, ST_SCAL=3'd3, ST_OUT=3'd4, ST_EMIT=3'd5;
    reg [2:0] state;
    reg [IC*8-1:0] in_latch;
    reg [3:0]      in_beat_idx;
    reg [4:0] pixel_row, pixel_col;
    reg [7:0] active_emit_count;
    reg [OC*8-1:0] out_pack;
    reg [5:0]      out_beat_idx;
    reg [7:0]  oc_group;
    reg [9:0]  k_counter;
    reg [1:0]  lane_counter;
    reg signed [ACC_W-1:0]    acc    [0:MP-1];
    reg signed [BIASED_W-1:0] biased [0:MP-1];
    reg signed [SCALED_W-1:0] scaled [0:MP-1];
    reg signed [7:0] weight_q, act_q;
    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] mul_q;
    reg [1:0] mac_lane_q1, mac_lane_q2;
    reg mac_valid_q1, mac_valid_q2, mac_done_issuing;
    integer i, lane, g_oc;
    reg signed [SCALED_W-1:0] v_tmp;
    reg signed [7:0] v_clamped;
    wire [19:0] weight_addr;
    wire signed [7:0] act_now;
    assign weight_addr = (oc_group * MP + lane_counter) * K_TOTAL + k_counter;
    assign act_now     = $signed(in_latch[k_counter*8 +: 8]);

    // Dedicated BRAM read path: synchronous, no reset.
    // Xilinx BRAM output registers do not support async reset; isolating
    // weight_q in a reset-free always block lets Vivado infer block ROM
    // for the weights[] array instead of distributed LUTRAM.
    always @(posedge clk) begin
        weight_q <= weights[weight_addr];
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state<=ST_LOAD; ready_in<=1'b1; valid_out<=1'b0; data_out<=256'b0;
            in_latch<={IC*8{1'b0}}; in_beat_idx<=4'd0;
            pixel_row<=5'd0; pixel_col<=5'd0; active_emit_count<=8'd0;
            out_pack<={OC*8{1'b0}}; out_beat_idx<=6'd0;
            oc_group<=8'd0; k_counter<=10'd0; lane_counter<=2'd0;
            act_q<=8'sd0; mul_q<={PROD_W{1'b0}};
            mac_lane_q1<=2'd0; mac_lane_q2<=2'd0;
            mac_valid_q1<=1'b0; mac_valid_q2<=1'b0; mac_done_issuing<=1'b0;
            for (i=0;i<MP;i=i+1) begin acc[i]<={ACC_W{1'b0}}; biased[i]<={BIASED_W{1'b0}}; scaled[i]<={SCALED_W{1'b0}}; end
        end else begin
            case (state)
                ST_LOAD: begin
                    valid_out <= 1'b0;
                    if (valid_in && ready_in) begin
                        in_latch[in_beat_idx*TILE_BITS +: TILE_BITS] <= data_in;
                        if (in_beat_idx == IN_BEATS-1) begin
                            in_beat_idx<=4'd0; ready_in<=1'b0;
                            k_counter<=10'd0; lane_counter<=2'd0; mac_done_issuing<=1'b0;
                            for (i=0;i<MP;i=i+1) acc[i]<={ACC_W{1'b0}};
                            state<=ST_RUN;
                        end else in_beat_idx <= in_beat_idx + 1'b1;
                    end
                end
                ST_RUN: begin
                    if (!mac_done_issuing) begin
                        act_q<=act_now;
                        mac_lane_q1<=lane_counter; mac_valid_q1<=1'b1;
                        if (lane_counter == MP-1) begin
                            lane_counter<=2'd0;
                            if (k_counter == K_TOTAL-1) begin k_counter<=10'd0; mac_done_issuing<=1'b1; end
                            else k_counter <= k_counter + 1'b1;
                        end else lane_counter <= lane_counter + 1'b1;
                    end else mac_valid_q1 <= 1'b0;
                    mul_q <= $signed(weight_q) * $signed(act_q);
                    mac_lane_q2 <= mac_lane_q1; mac_valid_q2 <= mac_valid_q1;
                    if (mac_valid_q2) acc[mac_lane_q2] <= acc[mac_lane_q2] + mul_q;
                    if (mac_done_issuing && !mac_valid_q1 && !mac_valid_q2) state <= ST_BIAS;
                end
                ST_BIAS: begin
                    for (lane=0;lane<MP;lane=lane+1) biased[lane] <= acc[lane] + biases[oc_group*MP + lane];
                    state <= ST_SCAL;
                end
                ST_SCAL: begin
                    for (lane=0;lane<MP;lane=lane+1) scaled[lane] <= biased[lane] * SCALE_MULT_CONST;
                    state <= ST_OUT;
                end
                ST_OUT: begin
                    for (lane=0;lane<MP;lane=lane+1) begin
                        g_oc = oc_group*MP + lane;
                        v_tmp = (scaled[lane] + (scaled[lane][SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                        v_clamped = (v_tmp > 127) ? 8'sd127 : (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];
                        out_pack[g_oc*8 +: 8] <= v_clamped;
                    end
                    if (oc_group == OC_PASSES-1) begin
                        oc_group<=8'd0;
                        out_beat_idx<=6'd1;
                        valid_out <= 1'b1;
                        data_out  <= out_pack[0 +: TILE_BITS];
                        state<=ST_EMIT;
                    end
                    else begin
                        oc_group <= oc_group + 1'b1;
                        for (lane=0;lane<MP;lane=lane+1) acc[lane]<={ACC_W{1'b0}};
                        k_counter<=10'd0; lane_counter<=2'd0; mac_done_issuing<=1'b0;
                        state<=ST_RUN;
                    end
                end
                ST_EMIT: begin
                    valid_out <= 1'b1;
                    data_out  <= out_pack[out_beat_idx*TILE_BITS +: TILE_BITS];
                    if (out_beat_idx == OUT_BEATS-1) begin
                        out_beat_idx<=6'd0; ready_in<=1'b1;
                        if (active_emit_count == OH_OW-1) begin
                            active_emit_count<=8'd0; pixel_row<=5'd0; pixel_col<=5'd0;
                        end else begin
                            active_emit_count <= active_emit_count + 1'b1;
                            if (pixel_col == OW-1) begin pixel_col<=5'd0; pixel_row<=pixel_row+1'b1; end
                            else pixel_col <= pixel_col + 1'b1;
                        end
                        state<=ST_LOAD;
                    end else out_beat_idx <= out_beat_idx + 1'b1;
                end
                default: state <= ST_LOAD;
            endcase
        end
    end
endmodule

